SELECT COUNT(*) > 0
FROM user_courses
WHERE user_id = #{userId}
  AND course_id = #{courseId}

SELECT COALESCE(
               COUNT(CASE WHEN lp.status = 'completed' THEN 1 END) * 1.0 / COUNT(*), 0
       ) AS progress_rate
FROM learning_progress lp
         JOIN sections s ON lp.section_id = s.id
         JOIN chapters ch ON s.chapter_id = ch.id
WHERE lp.user_id = #{userId}
  AND ch.course_id = #{courseId}

SELECT COUNT(*) > 0
FROM course_ratings
WHERE user_id = #{userId}
  AND course_id = #{courseId}
  AND is_deleted = 0

